import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

// BRAND COLORS
const gold = '#D4AF37'; 
const terracotta = '#C04000'; 
const clayLight = '#E2725B'; 
const softCream = '#FDF5E6'; 

const WigStore = () => {
  const categories = [
    { type: "Human Hair", items: [{ name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit" }] },
    { type: "Premium Fibre", items: [{ name: "Sleek Straight", price: "35,000", desc: "Heat Resistant" }] },
    { type: "Hair Blend", items: [{ name: "Piano Wavy", price: "25,000", desc: "24\" T-Closure" }] }
  ];

  return (
    <div style={{ padding: '0 20px', marginTop: '-10px' }}>
      {categories.map((cat) => (
        <div key={cat.type} style={{ marginBottom: '15px' }}>
          <h3 style={{ fontSize: '0.65rem', color: terracotta, textTransform: 'uppercase', letterSpacing: '1.5px', marginBottom: '8px' }}>{cat.type}</h3>
          {cat.items.map((item) => (
            <div key={item.name} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '12px', marginBottom: '8px', padding: '12px', alignItems: 'center', border: '1px solid #1a1a1a' }}>
              <div style={{ width: '55px', height: '55px', backgroundColor: '#000', borderRadius: '8px', marginRight: '12px' }}></div>
              <div style={{ flex: 1 }}>
                <h4 style={{ fontSize: '0.85rem', margin: '0', color: '#fff', fontWeight: '600' }}>{item.name}</h4>
                <p style={{ fontSize: '0.65rem', color: '#666', margin: '2px 0' }}>{item.desc}</p>
                <div style={{ fontSize: '0.9rem', fontWeight: 'bold', color: gold }}>₦{item.price}</div>
              </div>
              <button style={{ backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '20px', padding: '6px 14px', fontSize: '0.65rem', fontWeight: 'bold' }}>ADD</button>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
};

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);

  const slides = [
    { title: "SMALL CHOPS", subtitle: "Lagos' finest selection." },
    { title: "THE HAIR EDIT", subtitle: "Luxury units & blends." },
    { title: "OFFICE LUNCH", subtitle: "Premium corporate dining." }
  ];

  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 5000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, -apple-system, sans-serif', WebkitFontSmoothing: 'antialiased' }}>
      
      {/* 1. STICKY PREMIUM HEADER */}
      <header style={{ 
        padding: '10px 20px', 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        position: 'sticky', 
        top: 0, 
        backgroundColor: 'rgba(0,0,0,0.85)', // Glassmorphism effect
        backdropFilter: 'blur(10px)',
        zIndex: 1000,
        borderBottom: '1px solid #111'
      }}>
        <img src={Logo} alt="Logo" style={{ height: '55px', width: 'auto', objectFit: 'contain' }} />
        <div style={{ display: 'flex', gap: '18px', fontSize: '1.2rem', color: softCream }}>
          <span>👤</span>
          <span style={{ position: 'relative' }}>🛒
            <span style={{ position: 'absolute', top: '-5px', right: '-10px', background: terracotta, color: '#fff', borderRadius: '50%', padding: '2px 5px', fontSize: '0.6rem' }}>0</span>
          </span>
        </div>
      </header>

      {/* 2. TERRACOTTA HERO BANNER */}
      <div style={{ 
        width: '100%', 
        height: '140px', 
        position: 'relative', 
        overflow: 'hidden', 
        background: `linear-gradient(145deg, ${terracotta} 0%, ${clayLight} 100%)` 
      }}>
        {slides.map((slide, index) => (
          <div key={index} style={{
            position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
            opacity: index === currentSlide ? 1 : 0,
            transition: 'opacity 1.5s ease-in-out',
            display: 'flex', flexDirection: 'column', justifyContent: 'center', padding: '0 25px'
          }}>
            <h2 style={{ fontSize: '1.3rem', color: '#fff', fontWeight: '900', margin: 0, letterSpacing: '1px' }}>{slide.title}</h2>
            <p style={{ fontSize: '0.8rem', color: softCream, margin: '4px 0 0', opacity: 0.8 }}>{slide.subtitle}</p>
          </div>
        ))}
      </div>

      {/* 3. BUSINESS BRANDING */}
      <div style={{ padding: '20px 25px 5px' }}>
        <h1 style={{ fontSize: '1.2rem', margin: '0', color: '#fff', fontWeight: '800' }}>Àmí by T</h1>
        <p style={{ fontSize: '0.7rem', color: '#666', margin: '4px 0 15px' }}>● Opened · Closes 08:00 PM · Ikeja, Lagos</p>
        
        <div style={{ display: 'flex', gap: '10px' }}>
          <button style={{ flex: 1, padding: '10px', borderRadius: '8px', border: 'none', backgroundColor: softCream, color: '#000', fontWeight: 'bold', fontSize: '0.8rem' }}>Pickup</button>
          <button style={{ flex: 1, padding: '10px', borderRadius: '8px', border: `1px solid ${terracotta}`, backgroundColor: 'transparent', color: '#fff', fontSize: '0.8rem' }}>Delivery</button>
        </div>
      </div>

      {/* 4. SMOOTH CATEGORY NAV */}
      <div style={{ 
        display: 'flex', 
        gap: '10px', 
        overflowX: 'auto', 
        padding: '15px 25px', 
        scrollbarWidth: 'none',
        msOverflowStyle: 'none'
      }}>
        {['Small Chops', 'Office Lunch', 'Wigs', 'About'].map((item) => (
          <button 
            key={item} 
            onClick={() => setActiveCategory(item)}
            style={{ 
              whiteSpace: 'nowrap', padding: '8px 18px', borderRadius: '20px', border: 'none',
              backgroundColor: activeCategory === item ? terracotta : '#111',
              color: activeCategory === item ? '#fff' : '#888',
              fontSize: '0.75rem', fontWeight: '700',
              transition: 'all 0.3s ease'
            }}
          >
            {item}
          </button>
        ))}
      </div>

      {/* 5. MAIN CONTENT AREA */}
      <main style={{ paddingBottom: '100px', marginTop: '-10px' }}>
        <h3 style={{ padding: '0 25px 12px', fontSize: '1rem', color: terracotta, fontWeight: '700' }}>{activeCategory}</h3>
        
        {/* Render Sections */}
        <div style={{ opacity: 1, transition: 'opacity 0.5s' }}>
          {activeCategory === 'Wigs' && <WigStore />}
          {activeCategory === 'Small Chops' && <Menu />}
          {activeCategory === 'Office Lunch' && <Lunch />}
          {activeCategory === 'About' && (
             <div style={{ padding: '0 25px', color: '#888', fontSize: '0.85rem', lineHeight: '1.6' }}>
                <p>Àmí by T is a lifestyle brand dedicated to luxury tastes and premium style.</p>
                <p>Located in the heart of Lagos, we bring you the finest small chops, gourmet lunches, and elite hair units.</p>
             </div>
          )}
        </div>
      </main>

      {/* 6. FLOATING CHECKOUT BAR (Standard for Apps) */}
      <div style={{ 
        position: 'fixed', bottom: '20px', left: '50%', transform: 'translateX(-50%)',
        width: '90%', maxWidth: '400px', backgroundColor: terracotta, 
        padding: '15px', borderRadius: '15px', display: 'flex', 
        justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 10px 25px rgba(0,0,0,0.5)'
      }}>
        <div style={{ fontWeight: 'bold' }}>0 ITEMS</div>
        <div style={{ fontWeight: 'bold' }}>VIEW CART ₦0.00</div>
